CREATE TABLE IF NOT EXISTS t_category (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name VARCHAR(50) NOT NULL, description VARCHAR(200), sort_order INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS t_user (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, username VARCHAR(50) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, nickname VARCHAR(50), email VARCHAR(100), phone VARCHAR(20), avatar VARCHAR(500), role VARCHAR(20) NOT NULL DEFAULT 'USER', status SMALLINT DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS t_pet (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name VARCHAR(50) NOT NULL, category_id BIGINT, breed VARCHAR(50), age VARCHAR(20), gender VARCHAR(10), pet_size VARCHAR(20), color VARCHAR(30), health_status VARCHAR(100), vaccination VARCHAR(100), sterilization SMALLINT DEFAULT 0, description TEXT, cover_image VARCHAR(500), status VARCHAR(20) DEFAULT 'AVAILABLE', view_count INT DEFAULT 0, created_by BIGINT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS t_pet_image (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, pet_id BIGINT, url VARCHAR(500) NOT NULL, sort_order INT DEFAULT 0);
CREATE TABLE IF NOT EXISTS t_adoption (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, pet_id BIGINT, user_id BIGINT, real_name VARCHAR(50) NOT NULL, id_card VARCHAR(18) NOT NULL, phone VARCHAR(20) NOT NULL, address VARCHAR(200) NOT NULL, housing_type VARCHAR(50), has_experience SMALLINT DEFAULT 0, family_agreed SMALLINT DEFAULT 0, occupation VARCHAR(50), income_range VARCHAR(30), reason TEXT, status VARCHAR(20) DEFAULT 'PENDING', review_comment TEXT, reviewed_by BIGINT, reviewed_at TIMESTAMP, owner_review_comment TEXT, owner_reviewed_by BIGINT, owner_reviewed_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS t_favorite (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, user_id BIGINT, pet_id BIGINT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uk_user_pet UNIQUE (user_id, pet_id));
CREATE TABLE IF NOT EXISTS t_comment (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, pet_id BIGINT, user_id BIGINT, content TEXT NOT NULL, parent_id BIGINT DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
